 1	import React from 'react';
 2	import xbytes from 'xbytes';
 3	
 4	import { V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
 5	import { isEmpty } from '@kubevirt-utils/utils/utils';
 6	import { PrometheusEndpoint, usePrometheusPoll } from '@openshift-console/dynamic-plugin-sdk';
 7	import {
 8	  Chart,
 9	  ChartArea,
10	  ChartAxis,
11	  ChartGroup,
12	  ChartVoronoiContainer,
13	} from '@patternfly/react-charts';
14	import chart_color_blue_300 from '@patternfly/react-tokens/dist/esm/chart_color_blue_300';
15	import useDuration from '@virtualmachines/details/tabs/metrics/hooks/useDuration';
16	
17	import ComponentReady from '../ComponentReady/ComponentReady';
18	import useResponsiveCharts from '../hooks/useResponsiveCharts';
19	import { getUtilizationQueries } from '../utils/queries';
20	import { MILLISECONDS_MULTIPLIER, tickFormat, TICKS_COUNT } from '../utils/utils';
21	
22	type StorageThresholdChartProps = {
23	  vmi: V1VirtualMachineInstance;
24	};
25	
26	const GIB_IN_BYTES = 1024;
27	
28	const StorageWriteThresholdChart: React.FC<StorageThresholdChartProps> = ({ vmi }) => {
29	  const { currentTime, duration, timespan } = useDuration();
30	  const queries = React.useMemo(
31	    () => getUtilizationQueries({ duration, obj: vmi }),
32	    [vmi, duration],
33	  );
34	  const { height, ref, width } = useResponsiveCharts();
35	
36	  const [data] = usePrometheusPoll({
37	    endpoint: PrometheusEndpoint?.QUERY_RANGE,
38	    endTime: currentTime,
39	    namespace: vmi?.metadata?.namespace,
40	    query: queries?.FILESYSTEM_WRITE_USAGE,
41	    timespan,
42	  });
43	
44	  const storageWriteData = data?.data?.result?.[0]?.values;
45	
46	  const chartData = storageWriteData?.map(([x, y]) => {
47	    return { x: new Date(x * MILLISECONDS_MULTIPLIER), y: Number(y) / GIB_IN_BYTES };
48	  });
49	
50	  return (
51	    <ComponentReady isReady={!isEmpty(chartData)}>
52	      <div className="util-threshold-chart" ref={ref}>
53	        <Chart
54	          containerComponent={
55	            <ChartVoronoiContainer
56	              labels={({ datum }) => {
57	                return `Data written: ${xbytes(datum?.y, { fixed: 2, iec: true })}`;
58	              }}
59	              constrainToVisibleArea
60	            />
61	          }
62	          domain={{
63	            x: [currentTime - timespan, currentTime],
64	          }}
65	          height={height}
66	          padding={35}
67	          scale={{ x: 'time', y: 'linear' }}
68	          width={width}
69	        >
70	          <ChartAxis
71	            style={{
72	              ticks: { stroke: 'transparent' },
73	            }}
74	            axisComponent={<></>}
75	            tickCount={TICKS_COUNT}
76	            tickFormat={tickFormat(duration, currentTime)}
77	          />
78	          <ChartGroup>
79	            <ChartArea
80	              style={{
81	                data: {
82	                  stroke: chart_color_blue_300.value,
83	                },
84	              }}
85	              data={chartData}
86	            />
87	          </ChartGroup>
88	        </Chart>
89	      </div>
90	    </ComponentReady>
91	  );
92	};
93	
94	export default StorageWriteThresholdChart;

